-- 05_prediction_engine_schema.sql
-- Prediction engine tables: team strengths, simulation runs, and results.
-- Does NOT modify profiles, premium_codes, predictions, or match_results.

-- ── TEAM STRENGTH SNAPSHOTS ────────────────────────────────────────────────
-- One row per team per version (generated by scripts/build_team_strength.py).
CREATE TABLE IF NOT EXISTS team_strength_snapshots (
  id             UUID        DEFAULT gen_random_uuid() PRIMARY KEY,
  team_code      TEXT        NOT NULL,
  version        TEXT        NOT NULL DEFAULT '1.0',
  elo_intl       NUMERIC     NOT NULL,
  elo_club_avg   NUMERIC,
  strength_score NUMERIC     NOT NULL,
  method         TEXT        NOT NULL DEFAULT 'elo_intl_only',
  created_at     TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (team_code, version)
);

ALTER TABLE team_strength_snapshots ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "public read strengths" ON team_strength_snapshots;
CREATE POLICY "public read strengths"
  ON team_strength_snapshots FOR SELECT
  TO anon, authenticated
  USING (true);

-- ── SIMULATION RUNS ────────────────────────────────────────────────────────
-- Metadata for each Monte Carlo execution (generated by run_monte_carlo.py).
CREATE TABLE IF NOT EXISTS simulation_runs (
  id             UUID        DEFAULT gen_random_uuid() PRIMARY KEY,
  runs           INTEGER     NOT NULL,
  seed           INTEGER,
  version        TEXT        NOT NULL DEFAULT '1.0',
  scenario_name  TEXT        NOT NULL DEFAULT 'baseline',
  model_version  TEXT,
  is_active      BOOLEAN     NOT NULL DEFAULT false,
  completed_at   TIMESTAMPTZ,
  input_hash     TEXT,
  created_at     TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE simulation_runs
  ADD COLUMN IF NOT EXISTS scenario_name TEXT NOT NULL DEFAULT 'baseline',
  ADD COLUMN IF NOT EXISTS model_version TEXT,
  ADD COLUMN IF NOT EXISTS is_active BOOLEAN NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS completed_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS input_hash TEXT;

CREATE UNIQUE INDEX IF NOT EXISTS idx_simulation_runs_one_active_scenario
  ON simulation_runs (scenario_name)
  WHERE is_active = true;

CREATE INDEX IF NOT EXISTS idx_simulation_runs_active_created
  ON simulation_runs (is_active, created_at DESC);

ALTER TABLE simulation_runs ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "public read simulation runs" ON simulation_runs;
CREATE POLICY "public read simulation runs"
  ON simulation_runs FOR SELECT
  TO anon, authenticated
  USING (true);

-- ── SIMULATION GROUP STANDINGS ─────────────────────────────────────────────
-- Aggregated qualification probabilities per team per simulation run.
CREATE TABLE IF NOT EXISTS simulation_group_standings (
  id              UUID        DEFAULT gen_random_uuid() PRIMARY KEY,
  simulation_run  UUID        REFERENCES simulation_runs(id) ON DELETE CASCADE,
  team_code       TEXT        NOT NULL,
  qualified_pct   NUMERIC,
  first_pct       NUMERIC,
  second_pct      NUMERIC,
  third_pct       NUMERIC,
  best_third_pct  NUMERIC,
  fourth_pct      NUMERIC,
  points_pct      JSONB       NOT NULL DEFAULT '{}'::jsonb,
  created_at      TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE simulation_group_standings
  ADD COLUMN IF NOT EXISTS points_pct JSONB NOT NULL DEFAULT '{}'::jsonb;

ALTER TABLE simulation_group_standings ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "public read simulation standings" ON simulation_group_standings;
CREATE POLICY "public read simulation standings"
  ON simulation_group_standings FOR SELECT
  TO anon, authenticated
  USING (true);

-- Projected best-third groups for the same simulation run.
CREATE TABLE IF NOT EXISTS simulation_terceros_table (
  id              UUID        DEFAULT gen_random_uuid() PRIMARY KEY,
  simulation_run  UUID        REFERENCES simulation_runs(id) ON DELETE CASCADE,
  rank            INTEGER     NOT NULL,
  group_id        TEXT        NOT NULL,
  team_code       TEXT        NOT NULL,
  third_pct       NUMERIC,
  qualifies_pct   NUMERIC,
  avg_pts         NUMERIC,
  avg_gd          NUMERIC,
  avg_gf          NUMERIC,
  qualifies       BOOLEAN     DEFAULT false,
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (simulation_run, rank),
  UNIQUE (simulation_run, group_id)
);

ALTER TABLE simulation_terceros_table ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "public read terceros" ON simulation_terceros_table;
CREATE POLICY "public read terceros"
  ON simulation_terceros_table FOR SELECT
  TO anon, authenticated
  USING (true);

-- ── PLAYERS ────────────────────────────────────────────────────────────────
-- Supplement to data/teams.json for players not yet in the JSON file.
-- Manual entries only — no scraping. elo_player is optional (custom rating).
CREATE TABLE IF NOT EXISTS players (
  id          UUID        DEFAULT gen_random_uuid() PRIMARY KEY,
  team_code   TEXT        NOT NULL,
  shirt_number INTEGER,
  pos         TEXT,
  name        TEXT        NOT NULL,
  age         INTEGER,
  club        TEXT,
  club_country TEXT,
  elo_club    NUMERIC,
  elo_player  NUMERIC,
  titular     BOOLEAN     DEFAULT false,
  version     TEXT        NOT NULL DEFAULT '1.0',
  created_at  TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE players
  ADD COLUMN IF NOT EXISTS club_country TEXT;

CREATE UNIQUE INDEX IF NOT EXISTS idx_players_team_name_club_version
  ON players(team_code, name, club, version);

ALTER TABLE players ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "public read players" ON players;
CREATE POLICY "public read players"
  ON players FOR SELECT
  TO anon, authenticated
  USING (true);

-- Explicit Data API grants. RLS controls visible rows; grants control whether
-- the anon/authenticated/service_role roles can reach these tables at all.
GRANT SELECT ON TABLE
  team_strength_snapshots,
  simulation_runs,
  simulation_group_standings,
  simulation_terceros_table,
  players
TO anon, authenticated;

GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE
  team_strength_snapshots,
  simulation_runs,
  simulation_group_standings,
  simulation_terceros_table,
  players
TO service_role;

